app.post('/consent', (req, res) => {
  if (!req.session.userId || !req.session.authRequest) {
    return res.status(400).send('No authorization request in progress');
  }
  
  const { action } = req.body;
  const { client_id, redirect_uri, state } = req.session.authRequest;
  
  if (action !== 'approve') {
    const errorUrl = new URL(redirect_uri);
    errorUrl.searchParams.set('error', 'access_denied');
    errorUrl.searchParams.set('error_description', 'User denied the request');
    if (state) errorUrl.searchParams.set('state', state);
    return res.redirect(errorUrl.toString());
  }
  
  const authCode = generateSecureToken();
  const expiresAt = Date.now() + 600000;
  
  authorizationCodes.set(authCode, {
    client_id,
    redirect_uri,
    userId: req.session.userId,
    userEmail: req.session.userEmail,
    scope: req.session.authRequest.scope,
    expiresAt,
    used: false
  });
  
  delete req.session.authRequest;
  
  const callbackUrl = new URL(redirect_uri);
  callbackUrl.searchParams.set('code', authCode);
  if (state) callbackUrl.searchParams.set('state', state);
  
  res.redirect(callbackUrl.toString());
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret, refresh_token } = req.body;
  
  if (!grant_type) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'grant_type is required' });
  }
  
  if (grant_type === 'authorization_code') {
    if (!code || !redirect_uri || !client_id || !client_secret) {
      return res.status(400).json({ error: 'invalid_request', error_description: 'Missing required parameters' });
    }
    
    const client = registeredClients[client_id];
    if (!client) {
      return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
    }
    
    const hashedSecret = crypto.createHash('sha256').update(client_secret).digest('hex');
    if (client.client_secret !== hashedSecret) {
      return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
    }
    
    const authCodeData = authorizationCodes.get(code);
    if (!authCodeData) {
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid authorization code' });
    }
    
    if (authCodeData.used) {
      authorizationCodes.delete(code);
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code already used' });
    }
    
    if (Date.now() > authCodeData.expiresAt) {
      authorizationCodes.delete(code);
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code expired' });
    }
    
    if (authCodeData.client_id !== client_id || authCodeData.redirect_uri !== redirect_uri) {
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Code does not match client or redirect_uri' });
    }
    
    authCodeData.used = true;
    
    const accessToken = generateSecureToken(48);
    const refreshTokenValue = generateSecureToken(48);
    const accessTokenExpiresAt = Date.now() + 3600000;
    
    accessTokens.set(accessToken, {
      client_id,
      userId: authCodeData.userId,
      userEmail: authCodeData.userEmail,
      scope: authCodeData.scope,
      expiresAt: accessTokenExpiresAt
    });
    
    refreshTokens.set(refreshTokenValue, {
      client_id,
      userId: authCodeData.userId,
      userEmail: authCodeData.userEmail,
      scope: authCodeData.scope
    });
    
    authorizationCodes.delete(code);
    
    return res.json({
      access_token: accessToken,
      token_type: 'Bearer',
      expires_in: 3600,
      refresh_token: refreshTokenValue,
      scope: authCodeData.scope
    });
  } else if (grant_type === 'refresh_token') {
    if (!refresh_token || !client_id || !client_secret) {
      return res.status(400).json({ error: 'invalid_request', error_description: 'Missing required parameters' });
    }
    
    const client = registeredClients[client_id];
    if (!client) {
      return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
    }
    
    const hashedSecret = crypto.createHash('sha256').update(client_secret).digest('hex');
    if (client.client_secret !== hashedSecret) {
      return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
    }
    
    const refreshTokenData = refreshTokens.get(refresh_token);
    if (!refreshTokenData || refreshTokenData.client_id !== client_id) {
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid refresh token' });
    }
    
    const newAccessToken = generateSecureToken(48);
    const accessTokenExpiresAt = Date.now() + 3600000;
    
    accessTokens.set(newAccessToken, {
      client_id,
      userId: refreshTokenData.userId,
      userEmail: refreshTokenData.userEmail,
      scope: refreshTokenData.scope,
      expiresAt: accessTokenExpiresAt
    });
    
    return res.json({
      access_token: newAccessToken,
      token_type: 'Bearer',
      expires_in: 3600,
      scope: refreshTokenData.scope
    });
  } else {
    return res.status(400).json({ error: 'unsupported_grant_type', error_description: 'Only authorization_code and refresh_token grant types are supported' });
  }
});

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Missing or invalid authorization header' });
  }
  
  const token = authHeader.substring(7);
  const tokenData = accessTokens.get(token);
  
  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Invalid access token' });
  }
  
  if (Date.now() > tokenData.expiresAt) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'invalid_token', error_description: 'Access token expired' });
  }
  
  res.json({
    sub: tokenData.userId,
    email: tokenData.userEmail,
    email_verified: true
  });
});

app.post('/revoke', (req, res) => {
  const { token, token_type_hint, client_id, client_secret } = req.body;
  
  if (!token || !client_id || !client_secret) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing required parameters' });
  }
  
  const client = registeredClients[client_id];
  if (!client) {
    return res.status(401).json({ error: 'invalid_client' });
  }
  
  const hashedSecret = crypto.createHash('sha256').update(client_secret).digest('hex');
  if (client.client_secret !== hashedSecret) {
    return res.status(401).json({ error: 'invalid_client' });
  }
  
  if (token_type_hint === 'refresh_token' || refreshTokens.has(token)) {
    refreshTokens.delete(token);
  } else {
    accessTokens.delete(token);
  }
  
  res.status(200).send();
});

